/**
 * Simple Markdown Parser (Fallback)
 * Handles headers, lists, code blocks, bold, and paragraphs.
 */
(function() {
    function parseMarkdown(markdown) {
        if (!markdown) return '';
        
        let html = markdown;

        // Code blocks
        html = html.replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>');
        
        // Inline code
        html = html.replace(/`([^`]+)`/g, '<code>$1</code>');

        // Headers
        html = html.replace(/^# (.*$)/gm, '<h1>$1</h1>');
        html = html.replace(/^## (.*$)/gm, '<h2>$1</h2>');
        html = html.replace(/^### (.*$)/gm, '<h3>$1</h3>');
        html = html.replace(/^#### (.*$)/gm, '<h4>$1</h4>');

        // Bold
        html = html.replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>');
        html = html.replace(/__(.*)__/gim, '<strong>$1</strong>');

        // Lists (Unordered)
        html = html.replace(/^\s*[\-\*] (.*)/gm, '<ul><li>$1</li></ul>');
        html = html.replace(/<\/ul>\s*<ul>/g, ''); // Merge adjacent lists

        // Paragraphs (simple)
        // Split by double newlines to form paragraphs, but preserve code blocks
        // This is a naive implementation, might need improvement for complex nesting
        // For now, let's just convert single newlines to <br> if not in tags
        html = html.replace(/\n/g, '<br>');

        return html;
    }

    window.marked = {
        parse: parseMarkdown
    };
})();
